import{_ as e,o as t,c as o,a as r}from"./app.aeaf9fcc.js";const b=JSON.parse('{"title":"meat312 v. Wee786Harry, Jun 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/meat312_v_wee786harry_jun_2018.md","lastUpdated":1666477380000}'),a={name:"government/court-cases-precedents/meat312_v_wee786harry_jun_2018.md"},n=r('<h1 id="meat312-v-wee786harry-jun-2018" tabindex="-1">meat312 v. Wee786Harry, Jun 2018 <a class="header-anchor" href="#meat312-v-wee786harry-jun-2018" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With ArowShot presiding, on 17th June 2018, meat312 pearled Wee786Harry with charges of Breaking and Entering and Breaking Reinforcements. Wee786Harry was ordered to pay 32 diamonds and was put on probation.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>meat312</strong>:</p><blockquote><p>I&#39;ve pearled @Wee786Harry for breaking and entering into my home, breaking multiple reinforced chests and blocks.</p></blockquote><blockquote><p>Case now?</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>pick your defence harry</p></blockquote><blockquote><p>not me</p></blockquote><p><strong>Wee786Harry</strong>:</p><blockquote><p>i choose Tigen</p></blockquote><p><strong>Tigen</strong>:</p><blockquote><p>Alright, who dun fucked up. Tell me CALMLY what happened</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>bgbba, do you mimd sharing that link with the evidence i sent earlier. not at home</p></blockquote><blockquote><p>Basically, I call for the shitter Wee786Harry be exiled from Yoahtl.</p></blockquote><blockquote><p>My evidence speaks for itself.</p></blockquote><p><strong>Tigen</strong>:</p><blockquote><p>Reviewing the evidence currently.</p></blockquote><p><strong>Wee786Harry</strong>:</p><blockquote><p>my offering of 64 diamonds is still on table x</p></blockquote><p><strong>Tigen</strong>:</p><blockquote><p>Meat, do you have any record of what was in those chests? Any idea what was lost?</p></blockquote><blockquote><p>Also were all the logs showing Orannari on the snitch logs relevant in any way to the case?</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>No, posted for transparency, nothing to my knowledge was taken. However I think he intended to slowly break reinforcements until he hit the motherload</p></blockquote><blockquote><p>to avoid detection</p></blockquote><p><strong>Tigen</strong>:</p><blockquote><p>Alright, so this is pretty cut and dry. Given you&#39;re history Harry, action needs to be taken.</p></blockquote><blockquote><p>I want you to pay reps. 32d of what you offered to meat. You will be hereby put on probation, and any further cases brought up against you which succeed will result in exile. Additionally, if you bring up any more cases to the court and lose the case, you will be penalized for wasting the court&#39;s time.</p></blockquote><blockquote><p>2 week probabtion at least</p></blockquote><h4 id="mechanical-note-this-case-seems-to-have-an-incomplete-transcript-looks-like-theres-some-evidence-that-was-posted-or-shown-outside-of-where-the-transcript-was-recorded-says-arrowshot-is-presiding-but-tigen-is-clearly-the-judge-here" tabindex="-1"><em>mechanical note: this case seems to have an incomplete transcript? Looks like theres some evidence that was posted or shown outside of where the transcript was recorded. Says Arrowshot is presiding but Tigen is clearly the judge here</em> <a class="header-anchor" href="#mechanical-note-this-case-seems-to-have-an-incomplete-transcript-looks-like-theres-some-evidence-that-was-posted-or-shown-outside-of-where-the-transcript-was-recorded-says-arrowshot-is-presiding-but-tigen-is-clearly-the-judge-here" aria-hidden="true">#</a></h4>',33),s=[n];function i(c,l,h,p,d,u){return t(),o("div",null,s)}const k=e(a,[["render",i]]);export{b as __pageData,k as default};
